WarningTerminology: Regression vs. Classification



Do not get confused about the fact that it is called logistic regression but is used for classification tasks. Logistic regression provides an estimate of the probability that \(y=1\) for given \(x\), i.e., an estimate for \(p(y=1|x;w,b)\). To turn, this into a classification model, we also need a classification threshold value for \(p(y=1|x;w,b)\) above which we classify an observation as \(y=1\).


Figure 3.4 shows an interactive example of a logistic regression model. The left-hand side shows the data points and the regression line. The right-hand side shows the log-likelihood function with the red dot showing the value of the log-likelihood for the current value of \(w\). The goal is to find the weight \(w\) in the regression line that maximizes the log-likelihood function (we assumed \(b=0\) for simplicity).
If you enable the classification threshold \(t\), a data point is shown as dark blue if \(p(y=1|x;w,b) &gt; t\), otherwise, it is shown in light blue. Note how the value of the threshold affects the classification of the data points for points in the middle. Essentially, for each classification threshold, we have a different classification model. But how do we choose the classification threshold? This is a topic that we will discuss in the next section.
Logistic regression belongs to the class of generalized linear models with logit as the link function. We could write
\[\log\left(\frac{p}{1-p}\right)= b+\sum_{i=1}^m w_i x_{i,n}\]
where \(p=p(y_n=1|x_n;w,b)\), which separates the linear part on the right-hand side from the logit on the left-hand side.



{
    //
    const randomDataRange = [-2, 2];
    const loglikelihoodRange = [-20, -8];

    // Generate random data
    const seed = 0.25160386911120525; // a number in [0,1)
    const source = d3.randomLcg(seed);
    const rand = d3.randomUniform.source(source)();
    let x1Tmp = Array.from({length: 200}, rand).map((x) =&gt; (randomDataRange[1] - randomDataRange[0]) * x + randomDataRange[0]);
    let x2Tmp = Array.from({length: 200}, rand).map((x) =&gt; (randomDataRange[1] - randomDataRange[0]) * x + randomDataRange[0]);
    let pTmp = x1Tmp.map((x1, i) =&gt; 1/(1+Math.exp(-0.5 - 3 * x1 - 4 * x2Tmp[i] - 2 * Math.pow(x1, 2)))); // "True" model
    //(usSquare.includes("") ? 2 * Math.pow(x1, 2) : 0)
    let yTmp = pTmp.map((p) =&gt; Array.from({length: 1}, rand)[0] &lt; p ? 1 : 0);
    let randomData = prepareData(yTmp, x1Tmp, x2Tmp);

    function prepareData(yTmp, x1Tmp, x2Tmp) {

        let data = [];

        for (let i = 0; i &lt; x1Tmp.length; i += 1) {
            let dataPoint = {"x1": x1Tmp[i], "x2": x2Tmp[i], "y": yTmp[i]};
            data.push(dataPoint)
        }

        return data;

    }

    // Decision boundary
    let regData = computeDecisionBoundary(weight1, weight2, weight3, bias, 0.5, randomDataRange, 100)

    function computeDecisionBoundary(w1, w2, w3, b, t, inputRange, N) {

        let data = [];

        for (let i = 0; i &lt;= N; i += 1) {
            let x1 = inputRange[0] + i * (inputRange[1] - inputRange[0])/100;
            let x2 = 1/w2 * (-b - w1 * x1 - (useSquare.includes("") ? w3 * Math.pow(x1,2)  : 0) - Math.log((1-t)/t));
            x2 = Math.min(Math.max(x2, inputRange[0]), inputRange[1])
            let c = 1/(1+Math.exp(-b - w1 * x1 - w2 * x2 - 2 * Math.pow(x1, 2) + 3 * Math.pow(x1, 3)) &lt; t ? 0 : 1);
            let dataPoint = {"x1": x1, "x2": x2, "lb": inputRange[0], "ub": inputRange[1], "c0": 0, "c1": 1};
            data.push(dataPoint);
        }

        return data;

    }


    return Plot.plot({
            marginLeft: 40,
            marginTop: 20,
            width: width - 2,
            height: width * 2/3 - 2,
            x: { domain: randomDataRange, label: "x₁"},
            y: { domain: randomDataRange, label: "x₂"},
            color: {
                domain: [0, 1],
                scheme: "Category10"
            },
            marks: [
                Plot.frame(),
                Plot.dot(randomData, {x: "x1", y: "x2", r: 4, fill: "y"}),
                Plot.areaY(regData, {x: "x1", y: "x2", y2: "lb", fill: "c0", fillOpacity: 0.2}),
                Plot.areaY(regData, {x: "x1", y: "x2", y2: "ub", fill: "c1", fillOpacity: 0.2}),
                Plot.line(regData, {x: "x1", y: "x2"})
            ],

            nice: true
        })
}







